<?php
namespace WCSA\Auth; defined('ABSPATH') || exit; use WCSA\Support\Helpers;
final class UserService{ public function findByMobile(string $m){$q=new \WP_User_Query(['number'=>1,'count_total'=>false,'meta_query'=>[['key'=>'wcsa_mobile_e164','value'=>$m,'compare'=>'=']]]);$u=$q->get_results();return $u?$u[0]:null;} public function login(\WP_User $u):void{wp_set_current_user($u->ID);wp_set_auth_cookie($u->ID,true);do_action('wp_login',$u->user_login,$u);} public function create(string $m,string $first,string $last,string $nc){$mob=Helpers::mobileNational($m);$username=preg_replace('/\D/','',$mob);if(!$username)$username='u'.wp_generate_password(10,false);$base=$username;$i=1;while(username_exists($username)){$username=$base.'_'.$i++;}$email=preg_replace('/\D/','',$mob).'@example.invalid'; if(email_exists($email))$email=preg_replace('/\D/','',$mob).'+'.wp_generate_password(6,false,false).'@example.invalid'; $id=wp_insert_user(['user_login'=>$username,'user_pass'=>wp_generate_password(24,true,true),'user_email'=>$email,'first_name'=>$first,'last_name'=>$last,'display_name'=>trim($first.' '.$last),'role'=>get_role('customer')?'customer':'subscriber']); if(is_wp_error($id))return $id; update_user_meta($id,'wcsa_mobile_e164',$m);update_user_meta($id,'wcsa_national_code',$nc);update_user_meta($id,'billing_phone',$mob);update_user_meta($id,'billing_first_name',$first);update_user_meta($id,'billing_last_name',$last); return get_user_by('id',$id);}}
